  ('immigration-1aab856d-moex-00003', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '2019年，美國國土安全部推出「國家關鍵功能」（NationalCriticalFunctions）的分析框架，旨在 透過使用何種視角（lens）來理解跨及多個部門的關鍵基礎設施之相互依賴關係？', '["任務視角", "功能視角", "行動視角", "法律視角"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00004', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '關鍵基礎設施提供的商品和服務是國家和經濟安全以及所有人民福祉的支柱，而其中居於重要地 位之四項生命線領域包括了電信、能源、交通以及下列那一項領域？', '["糧食", "太空", "經貿", "水和廢水"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00005', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '為有效應對恐怖主義威脅，減緩可能嫌疑犯之危害，公私部門必須合作以事先發掘可能進行攻擊 之可疑行動，其中過程不僅涉及資訊流動且可鑑定出各式各樣資訊分享之參與者。下列何者不是 此過程之必要工作？', '["規劃與指導", "分析與產品", "蒐集與處理", "檢討與韌性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00006', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '在國土安全脈絡下，國土防衛與民事支援之互動，是透過下列那一項工作來進行整合？', '["非戰爭軍事行動", "應對混合戰爭", "緊急事件準備", "民事行動"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00007', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '國家關鍵基礎設施必須先經過篩選，以集中資源及排列優先順序來進行事態防範，而在進行國家 關鍵基礎設施盤點時，下列何者不是基本篩選原則？', '["足以直接或間接造成大規模人口傷亡或避難遷徙者", "足以直接或間接造成重大國防損失者", "足以直接或間接影響其他關鍵基礎設施營運之能力者", "足以影響政府功能持續運作、民心士氣、社會安定者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00008', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '美國國土安全部在「全國回應計畫」（NationalResponsePlan）中指出，國土安全部負責機關間 的情報，提供情勢警訊方面的威脅／情報，預測後續威脅活動，以及維持與其他國家情報機關的 及時通信鏈接。且有四項必須達成之目標，下列何者不是此等目標之一？', '["能力培養", "人力甄補", "夥伴關係", "反情報"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00009', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '我國於 2024 年 6 月 19 日成立「全社會防衛韌性委員會」，推動建構國家韌性戰略溝通協調平 臺，由何人擔任召集人？', '["總統", "副總統", "行政院長", "國防部長"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
